/* This pass counts the number of basic blocks in each function
   and outputs the results via dump_file for debugging purposes. */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "dumpfile.h"
#include "basic-block.h"
#include "function.h"

namespace {

const pass_data pass_data_count_bbs =
{
  GIMPLE_PASS, /* type */
  "count_bbs", /* name */
  OPTGROUP_NONE, /* optinfo_flags */
  TV_NONE, /* tv_id */
  0, /* properties_required */
  0, /* properties_provided */
  0, /* properties_destroyed */
  0, /* todo_flags_start */
  0, /* todo_flags_finish */
};

/* Pass class that counts basic blocks per function. */
class pass_count_bbs : public gimple_opt_pass
{
public:
  pass_count_bbs (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bbs, ctxt)
  {
  }

  /* opt_pass methods: */
  opt_pass * clone () final override
  {
    return new pass_count_bbs (m_ctxt);
  }

  /* Gate function always returns true to allow pass to run. */
  bool gate (function *) final override
  {
    return true;
  }

  /* Execute the pass: count and report basic blocks per function. */
  unsigned int execute (function *fun) final override
  {
    basic_block bb;
    int bb_count = 0;

    /* Count all basic blocks in the function. */
    FOR_EACH_BB_FN (bb, fun)
    {
      bb_count++;
    }

    /* Output results to dump file if available. */
    if (dump_file)
    {
      fprintf (dump_file, "Function '%s' has %d basic blocks\n",
               function_name (fun), bb_count);

      /* If we want more detailed output, iterate and print info. */
      if (dump_flags & TDF_DETAILS)
      {
        fprintf (dump_file, "Basic blocks details:\n");
        int bb_index = 0;
        FOR_EACH_BB_FN (bb, fun)
        {
          fprintf (dump_file, "  BB %d: index=%d, count=%d\n",
                   bb_index++, bb->index,
                   (int)bb->count.value ());
        }
      }
    }

    return 0;  /* No TODO items needed. */
  }

}; // class pass_count_bbs

} // anon namespace

gimple_opt_pass *
make_pass_count_bbs (gcc::context *ctxt)
{
  return new pass_count_bbs (ctxt);
}

/* Declaration for basic block counter pass.
   This snippet should be added to gcc/tree-pass.h */

/* Declare the factory function for the basic block counter pass. */
extern gimple_opt_pass *make_pass_count_bbs (gcc::context *ctxt);

